var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"누구 말을 듣는 사람들이 아니라고?","JPN":"誰かの言葉に従うやつらじゃないだって？","ENG":"Don't take orders from anyone, huh?","TWN":"不會聽別人的話？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"하, 하지만 지금 너희는 관리국 명령으로 움직이고 있는 거 아냐?","JPN":"で、でも現に管理局の命令で動いてるじゃないか？","ENG":"B-but aren't you all just mobilizing because the Administration told you to?","TWN":"哈，但你們現在不是在執行管理局的命令嗎？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"너, 바다로 나와본 적, 별로 없지?","JPN":"お前、海に出たこと、あんまないだろ？","ENG":"You haven't really been out on the ocean much, have you?","TWN":"妳很少出海吧？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"……아니? 아닌데?","JPN":"……いや？　そんなことないけど？","ENG":"...No? I have!","TWN":"……沒有啊？才不是呢？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이 시대의 대해적이 될 사람이 바다에 나와본 적이 별로 없다는 게 말이나 돼?","JPN":"この時代の大海賊になろうってやつが海に出たことがないなんて、あり得ないだろ。","ENG":"How could someone who's going to be the era's great pirate not have gone out to sea?!","TWN":"要成為這個時代大海盜的人竟然很少出海，這能說得通嗎？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하핫! 거짓말이 서투르시구만?","JPN":"キャハハッ！　お前嘘がヘタクソだな。","ENG":"Kyahaha! You're terrible at lying.","TWN":"哈哈哈！謊言真拙劣呢？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"저 해적들은 관리국의 명령이 아니라 관리국이 주는 현상금을 보고 움직이는 거야.","JPN":"あの海賊たちは管理局の命令じゃなくて、管理局から出る賞金目当てで動いてるんだ。","ENG":"Those pirates aren't following Administration orders. They're following the bounty the Administration's offering.","TWN":"那些海盜不是聽管理局命令，而是看管理局給的賞金行動。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"헌터들도 관리국에 정당한 의뢰금을 받고 활동하는 거라고.","JPN":"ハンターたちも管理局からちゃんとした依頼金をもらって活動してる。","ENG":"Hunters work because they're getting proper commission fees.","TWN":"獵人也是拿到合理報酬才會行動。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"살아남기 위해선 손을 잡지만, 언제든 등을 돌릴 수 있는 사이.","JPN":"生き残るためには協力もするけど、いつでも手を切れる仲。","ENG":"We join hands to survive, but we can turn on each other anytime.","TWN":"他們為了生存會暫時合作，但隨時可能翻臉。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그게 최근의 해적과 헌터의 관계라고 볼 수 있지.","JPN":"それが最近の海賊とハンターの関係だな。","ENG":"That's the current relationship between pirates and hunters.","TWN":"這就是最近海盜和獵人的關係。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"대해적이 되고 싶은 꿈나무라면 반드시 변화하는 상황을 숙지하도록!","JPN":"大海賊になりたいなら、状況の移り変わりくらいは必ず熟知すること！","ENG":"And if you want to be a great pirate someday, get used to how things change.","TWN":"如果你夢想成為大海盜，一定要掌握局勢變化！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이게… 완전히 얼뜨기 취급하고 있어?!","JPN":"このっ……完全にばかにしてるだろ！？","ENG":"They're... treating me like a complete rookie?!","TWN":"這……是把我當笨蛋看待嗎？！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"들켰는데?","JPN":"バレたね。","ENG":"She caught on.","TWN":"被發現了嗎？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하핫, 생긴 것과 다르게 놀리는 재미가 있구만.","JPN":"キャハハッ、見た目のわりにからかい甲斐があるやつだな。","ENG":"Kyahaha! You don't look it, but you're fun to tease.","TWN":"哈哈哈，妳和外表不同，很幽默呢。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"예전부터 궁금했는데 말이지.","JPN":"前から気になってたんだけど。","ENG":"I've wondered for a while now.","TWN":"我從剛剛開始就一直很好奇。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"너는 왜 대해적이 되려는 거야?","JPN":"お前はなんで大海賊になろうとしてるんだ？","ENG":"Why do you want to become a great pirate?","TWN":"小姐為什麼想成為大海盜？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"선상 반란 때를 생각해 보면… 그 실력으로 해적이 될 필요는 없어 보였거든.","JPN":"船上反乱の時もそうだけど……その腕で海賊になる必要なんかなさそうに思えたからさ。","ENG":"Thinking back to the rebellion... with your skills, you don't need to become a pirate at all.","TWN":"回想船上叛亂時……妳那種實力根本不需要當海盜。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"당연히 사람들의 자유를 억압하는 관리국으로부터 도시를 해방하기 위해서지.","JPN":"そりゃ決まってるだろ。みんなの自由を抑圧してる管理局から都市を解放するため。","ENG":"Obviously because I want to free the city from the Administration that's been oppressing people's freedom.","TWN":"當然是為了從壓迫人民自由的管理局手中解放城市。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"관리국은 바다를 통제하고, 많은 사람의 자유를 빼앗았어.","JPN":"管理局は海を統制して、多くの人の自由を奪った。","ENG":"The Administration controls the ocean and has stolen people's freedom.","TWN":"管理局控制海洋，剝奪許多人自由。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"해적들은 허락 없이 바다로 나갔다는 이유로 범죄자가 되었잖아.","JPN":"海賊は、許可なく海に出たっていう理由で犯罪者になったじゃないか。","ENG":"Pirates became criminals just for going out to sea without permission.","TWN":"海盜因為未經許可出海而成了罪犯。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그런 관리국의 횡포에 화가 나지도 않아?","JPN":"そんな管理局の横暴に怒りが沸かないのか？","ENG":"Doesn't that piss you off?","TWN":"你們都不會因為管理局的橫蠻而生氣嗎？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐어?","JPN":"はあ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭔가 단단히 착각하고 있는 것 같네.","JPN":"何かとんでもねえ勘違いをしてるぞ。","ENG":"You've got this all wrong.","TWN":"小姐好像誤會了。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"해적은 육지의 규칙에 신경 쓰지 않아.","JPN":"海賊は陸の規則なんて気にしない。","ENG":"Pirates don't care about the rules on land.","TWN":"海盜並不在意陸地的規則。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"우리가 자유를 억압당하는 게 싫어서 해적이 되었나?","JPN":"あたしたちは自由を抑圧されたくなくて海賊になったのか？","ENG":"Do you think we became pirates because we hate being \\"oppressed\\"?","TWN":"我們成為海盜，是因為不想被剝奪自由嗎？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"아니지.","JPN":"違うよね。","ENG":"Nope.","TWN":"當然不是。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"관리국이 해적들을 쥐 잡듯이 잡고, 우리의 활동을 제한하고 있나?","JPN":"管理局が厳しくあたしたち海賊の活動を制限してる？","ENG":"Is the Administration hunting us like rats and restricting all our activities?","TWN":"管理局像抓老鼠一樣抓海盜，限制我們的活動嗎？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그것도 아니야.","JPN":"それも違うな。","ENG":"Not that either.","TWN":"也不是。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"소냐, 네가 해적이 되면서까지 바다로 나오게 된 이유는?","JPN":"ソーニャ、お前が海賊になってまで海に出た理由は？","ENG":"Sonya, why did you go out to sea and become a pirate?","TWN":"索妮雅，妳成為海盜出海的理由是什麼？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"갓 잡은 신선한 생선을 먹기 위해서.","JPN":"釣ったばかりの新鮮な魚を食べるために。","ENG":"To eat freshly caught fish.","TWN":"為了吃剛捕到的新鮮魚隻。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};